,p_plug_name=>'New'
,p_static_id=>'new'
,p_region_template_options=>'#DEFAULT#:t-CardsRegion--hideHeader js-addHiddenHeadingRoleDesc'
,p_plug_template=>2074200852440250129
,p_plug_display_sequence=>10
,p_plug_item_display_point=>'ABOVE'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ''Total Donors'' AS label,',
'       TO_CHAR(COUNT(*)) AS value,',
'       ''fa-heart'' AS icon,',
'       ''u-color-1-bg'' AS color',
'FROM donor',
'UNION ALL',
'SELECT ''Available Units'',',
'       TO_CHAR(COUNT(*)),',
'       ''fa-tint'',',
'       ''u-color-2-bg''',
'FROM blood_unit WHERE status = ''AVAILABLE''',
'UNION ALL',
'SELECT ''Hospitals'',',
'       TO_CHAR(COUNT(*)),',
'       ''fa-hospital-o'',',
'       ''u-color-3-bg''',
'FROM hospital',
'UNION ALL',
'SELECT ''Pending Requests'',',
'       TO_CHAR(COUNT(*)),',
'       ''fa-clock-o'',',
'       ''u-color-4-bg''',
'FROM request WHERE status = ''PENDING''',
'UNION ALL',
'SELECT ''Critical Requests'',',
'       TO_CHAR(COUNT(*)),',
'       ''fa-exclamation-circle'',',
'       ''u-color-5-bg''',
'FROM request WHERE urgency = ''CRITICAL''',
'UNION ALL',
'SELECT ''Active Staff'',',
'       TO_CHAR(COUNT(*)),',
'       ''fa-id-badge'',',
'       ''u-color-6-bg''',
'FROM staff WHERE is_active = ''Y''',
'UNION ALL',
'SELECT ''Total Patients'',',
'       TO_CHAR(COUNT(*)),',
'       ''fa-user-md'',',
'       ''u-color-7-bg''',
'FROM patient',
'UNION ALL',
'SELECT ''Donation Camps'',',
'       TO_CHAR(COUNT(*)),',
'       ''fa-flag'',',
'       ''u-color-8-bg''',
'FROM donation_camp'))
,p_lazy_loading=>false
,p_plug_source_type=>'NATIVE_CARDS'
,p_plug_query_num_rows_type=>'SCROLL'
,p_show_total_row_count=>false
