,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    d.donor_id        AS "ID",',
'    d.full_name       AS "Donor Name",',
'    d.blood_type      AS "Blood Type",',
'    d.gender          AS "Gender",',
'    d.city            AS "City",',
'    d.contact_no      AS "Contact",',
'    d.is_eligible     AS "Eligible",',
'    COUNT(bu.unit_id) AS "Total Donations",',
'    MAX(bu.collection_date) AS "Last Donation"',
'FROM donor d',
'LEFT JOIN blood_unit bu ON d.donor_id = bu.donor_id',
'GROUP BY d.donor_id, d.full_name, d.blood_type,',
'         d.gender, d.city, d.contact_no, d.is_eligible',
'ORDER BY "Total Donations" DESC'))
