,p_plug_name=>'Inventory Report'
,p_static_id=>'inventory-report'
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_plug_template=>2102002977963900996
,p_plug_display_sequence=>10
,p_plug_item_display_point=>'ABOVE'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    bb.bank_name         AS "Blood Bank",',
'    bb.city              AS "City",',
'    bu.blood_type        AS "Blood Type",',
'    COUNT(*)             AS "Total Units",',
'    SUM(CASE WHEN bu.status = ''AVAILABLE'' THEN 1 ELSE 0 END) AS "Available",',
'    SUM(CASE WHEN bu.status = ''RESERVED''  THEN 1 ELSE 0 END) AS "Reserved",',
'    SUM(CASE WHEN bu.status = ''USED''      THEN 1 ELSE 0 END) AS "Used",',
'    SUM(CASE WHEN bu.status = ''EXPIRED''   THEN 1 ELSE 0 END) AS "Expired",',
'    MIN(bu.expiry_date)  AS "Nearest Expiry"',
'FROM blood_unit bu',
'JOIN blood_bank bb ON bu.bank_id = bb.bank_id',
'GROUP BY bb.bank_name, bb.city, bu.blood_type',
'ORDER BY bb.bank_name, bu.blood_type'))
,p_plug_source_type=>'NATIVE_IR'
