,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    r.request_id       AS "ID",',
'    h.hosp_name        AS "Hospital",',
'    h.city             AS "City",',
'    r.blood_type       AS "Blood Type",',
'    r.qty_needed       AS "Qty Needed",',
'    r.urgency          AS "Urgency",',
'    r.status           AS "Status",',
'    r.request_date     AS "Requested On",',
'    r.fulfilled_date   AS "Fulfilled On",',
'    CASE ',
'        WHEN r.status = ''FULFILLED'' ',
'        THEN r.fulfilled_date - r.request_date',
'        ELSE NULL ',
'    END                AS "Days to Fulfill"',
'FROM request r',
'JOIN hospital h ON r.hospital_id = h.hospital_id',
'ORDER BY r.request_date DESC'))
