,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    dc.camp_id          AS "Camp ID",',
'    bb.bank_name        AS "Organized By",',
'    dc.location         AS "Location",',
'    dc.city             AS "City",',
'    dc.camp_date        AS "Camp Date",',
'    dc.organizer_name   AS "Organizer",',
'    dc.target_units     AS "Target Units",',
'    dc.actual_units     AS "Actual Units",',
'    COUNT(cp.participation_id) AS "Participants",',
'    ROUND(dc.actual_units/NULLIF(dc.target_units,0)*100) || ''%'' AS "Achievement"',
'FROM donation_camp dc',
'JOIN blood_bank bb ON dc.bank_id = bb.bank_id',
'LEFT JOIN camp_participation cp ON dc.camp_id = cp.camp_id',
'GROUP BY dc.camp_id, bb.bank_name, dc.location,',
'         dc.city, dc.camp_date, dc.organizer_name,',
'         dc.target_units, dc.actual_units',
'ORDER BY dc.camp_date DESC'))
